#include "dps310.h"
#include <Wire.h>
#include <Adafruit_DPS310.h>
static Adafruit_DPS310 dps;
static float _p=0,_t=0,_a=0;static unsigned long _l=0;
void dps310_setup(){Wire.begin();if(!dps.begin_I2C()){Serial.println("[dps310] Fail!");return;}dps.configurePressure(DPS310_64HZ,DPS310_64SAMPLES);dps.configureTemperature(DPS310_64HZ,DPS310_64SAMPLES);Serial.println("[dps310] OK");}
void dps310_loop(){if(millis()-_l<1000)return;_l=millis();sensors_event_t te,pe;dps.getEvents(&te,&pe);_t=te.temperature;_p=pe.pressure;_a=44330.0*(1.0-pow(_p/1013.25,0.1903));}
float dps310_get_pressure(){return _p;}
float dps310_get_temperature(){return _t;}
float dps310_get_altitude(){return _a;}
